mapper.select:
select a.*,b.name as create_org_name,c.name as range_name from xm_notice a left join sys_org b on a.create_org_id = b.id left join sys_org c on a.range_id = c.id where a.is_delete = 0 and a.create_by = #{userId} and a.type = #{type}
and a.title like concat('%', #{title}, '%')
order by a.create_time desc
